step.commands:
# Update GitHub issue fields gh issue edit {STORY_NUMBER} \ --add-field "AAFD Stage=Implementation" \ --add-field "AI Context Status=Loaded" \ --add-field "Implementation Phase=Analysis"
# Add implementation start comment gh issue comment {STORY_NUMBER} \ --body "🚀 Starting implementation of story #{STORY_NUMBER}
**Session Start**: $(date) **Developer**: @me **Branch**: feature/story-{STORY_NUMBER}-{BRIEF_DESCRIPTION}"


# Create feature branch
git checkout -b feature/story-{STORY_NUMBER}-{BRIEF_DESCRIPTION}

# Push branch to remote
git push -u origin feature/story-{STORY_NUMBER}-{BRIEF_DESCRIPTION}

step.example:

// apps/web/app/home/(user)/editor/_actions/generate-content.test.ts
import { describe, it, expect, beforeEach } from 'vitest';
import { generateContentAction } from './generate-content.action';
import { createMockUser } from '@/tests/factories/user';
import { mockPortkeyResponse } from '@/tests/mocks/portkey';

describe('generateContentAction', () => {
  beforeEach(() => {
    // Reset mocks
    vi.clearAllMocks();
  });

  describe('validation', () => {
    it('should reject empty prompt', async () => {
      const user = createMockUser();
      const input = { prompt: '', slideId: 'slide-123' };

      await expect(generateContentAction(input, user))
        .rejects.toThrow('Prompt must be at least 3 characters');
    });

    it('should reject invalid slideId', async () => {
      const user = createMockUser();
      const input = { prompt: 'Valid prompt', slideId: '' };

      await expect(generateContentAction(input, user))
        .rejects.toThrow('Valid slide ID required');
    });
  });

  describe('content generation', () => {
    it('should generate content successfully', async () => {
      const user = createMockUser();
      const input = { 
        prompt: 'Create a slide about AI benefits',
        slideId: 'slide-123'
      };

      mockPortkeyResponse({
        content: 'AI Benefits: 1. Automation...',
        usage: { tokens: 150 }
      });

      const result = await generateContentAction(input, user);

      expect(result.success).toBe(true);
      expect(result.content).toContain('AI Benefits');
      expect(result.usage.tokens).toBe(150);
    });

    it('should complete within 5 seconds', async () => {
      const user = createMockUser();
      const input = { 
        prompt: 'Create a slide about AI',
        slideId: 'slide-123'
      };

      const start = Date.now();
      await generateContentAction(input, user);
      const duration = Date.now() - start;

      expect(duration).toBeLessThan(5000);
    });
  });
});

